fn execute(input: &serde_json::Value) -> serde_json::Value {
    let items = input.get("items").and_then(|v| v.as_array()).cloned().unwrap_or_default();
    let n = input.get("n").and_then(|v| v.as_u64()).unwrap_or(0) as usize;
    let taken: Vec<_> = items.into_iter().take(n).collect();
    serde_json::Value::Array(taken)
}
